create table if not exists inspection_result_repair_audit (
  id bigint not null auto_increment primary key,
  tenant_id bigint not null,
  inspection_record_id varchar(120) not null,
  original_standard_version_id bigint null,
  original_standard_version varchar(64) null,
  original_full_score decimal(8,2) not null,
  original_pass_score decimal(8,2) null,
  original_score decimal(8,2) not null,
  original_material_score decimal(8,2) null,
  original_hygiene_score decimal(8,2) null,
  original_service_score decimal(8,2) null,
  original_result_code varchar(32) null,
  original_passed tinyint not null,
  repaired_standard_version_id bigint not null,
  repaired_standard_version varchar(64) null,
  repaired_full_score decimal(8,2) null,
  repaired_pass_score decimal(8,2) null,
  repaired_score decimal(8,2) null,
  repaired_material_score decimal(8,2) null,
  repaired_hygiene_score decimal(8,2) null,
  repaired_service_score decimal(8,2) null,
  repaired_result_code varchar(32) null,
  repaired_passed tinyint null,
  repair_status varchar(32) not null,
  repair_reason varchar(500) not null,
  snapshot_item_count int not null default 0,
  expected_item_count int not null default 0,
  repaired_by bigint null,
  repaired_at timestamp not null default current_timestamp,
  index idx_inspection_result_repair_record (
    tenant_id, inspection_record_id, repaired_at
  ),
  index idx_inspection_result_repair_status (
    tenant_id, repair_status, repaired_at
  ),
  constraint uk_inspection_result_repair_target
    unique (tenant_id, inspection_record_id, repaired_standard_version_id),
  constraint chk_inspection_result_repair_status
    check (repair_status in ('RECALCULATED', 'MANUAL_REVIEW')),
  constraint fk_inspection_result_repair_tenant
    foreign key (tenant_id) references tenant(id),
  constraint fk_inspection_result_repair_record
    foreign key (inspection_record_id) references inspection_record(id),
  constraint fk_inspection_result_repair_original_standard
    foreign key (original_standard_version_id) references inspection_standard_version(id),
  constraint fk_inspection_result_repair_repaired_standard
    foreign key (repaired_standard_version_id) references inspection_standard_version(id),
  constraint fk_inspection_result_repair_user
    foreign key (repaired_by) references auth_user(id)
);

drop table if exists v40_quality_item_template;

create table v40_quality_item_template (
  dimension varchar(120) not null,
  code varchar(80) not null,
  title varchar(500) not null,
  description longtext null,
  check_method longtext null,
  suggested_score decimal(8,2) not null,
  red_line tinyint(1) not null,
  risk_level varchar(16) not null,
  category_score decimal(8,2) not null,
  source_sheet varchar(120) not null,
  source_row int not null,
  subitems_json longtext not null,
  sort_order int not null,
  constraint chk_v40_quality_template_risk
    check (risk_level in ('NORMAL', 'RED', 'YELLOW'))
);

insert into v40_quality_item_template(
  dimension, code, title, description, check_method, suggested_score,
  red_line, risk_level, category_score, source_sheet, source_row,
  subitems_json, sort_order
)
values
  ('物料标准', 'M-RED-01', '1.是否存在背后议论顾客，和顾客发生言语冲突，肢体冲突问题,是否出现服务态度恶劣，不理睬顾客,对于进店和离店顾客是否使有礼貌欢送用语等', '1.是否存在背后议论顾客，和顾客发生言语冲突，肢体冲突问题,是否出现服务态度恶劣，不理睬顾客,对于进店和离店顾客是否使有礼貌欢送用语等', '1.禁止出现争吵以及辱骂顾客行为； 2.禁止在店铺议论顾客 3.顾客进店询问，任何岗位人员都要回应顾客，切记不要出现不理会的现象等； 4.跟顾客沟通的时候，语调及肢体不可出现不礼貌行为，不可出现不耐烦的现象等； 5.如前台出现多位顾客等候，耐心服务当前顾客，及时安抚后面顾客，并告知等待时长，切记不能出现不告知不理会现象等', 0, 1, 'RED', 37, '物料标准', 4, '[{"code":"M-RED-01","sourceRow":4,"title":"1.是否存在背后议论顾客，和顾客发生言语冲突，肢体冲突问题,是否出现服务态度恶劣，不理睬顾客,对于进店和离店顾客是否使有礼貌欢送用语等","checkMethod":"1.禁止出现争吵以及辱骂顾客行为； 2.禁止在店铺议论顾客 3.顾客进店询问，任何岗位人员都要回应顾客，切记不要出现不理会的现象等； 4.跟顾客沟通的时候，语调及肢体不可出现不礼貌行为，不可出现不耐烦的现象等； 5.如前台出现多位顾客等候，耐心服务当前顾客，及时安抚后面顾客，并告知等待时长，切记不能出现不告知不理会现象等"}]', 1),
  ('物料标准', 'M-RED-02', '2.产品制作不得随意更改配方并且按照标准流程制作', '2.产品制作不得随意更改配方并且按照标准流程制作', '1.按照标准SOP进行产品制作', 0, 1, 'RED', 37, '物料标准', 5, '[{"code":"M-RED-02","sourceRow":5,"title":"2.产品制作不得随意更改配方并且按照标准流程制作","checkMethod":"1.按照标准SOP进行产品制作"}]', 2),
  ('物料标准', 'M-RED-03', '3.时效标签是否存在篡改日期行为； 报损是否按真实日期填写；', '3.时效标签是否存在篡改日期行为； 报损是否按真实日期填写；', '1.水果及物料到货按真实日期填写 2.到店货物（味全，卡士，牛奶）不允许超过一周 3.过期和变质发霉食品严禁使用', 0, 1, 'RED', 37, '物料标准', 6, '[{"code":"M-RED-03","sourceRow":6,"title":"3.时效标签是否存在篡改日期行为； 报损是否按真实日期填写；","checkMethod":"1.水果及物料到货按真实日期填写 2.到店货物（味全，卡士，牛奶）不允许超过一周 3.过期和变质发霉食品严禁使用"}]', 3),
  ('物料标准', 'M-RED-04', '4.严禁在店铺传播负能量，影响店铺氛围。', '4.严禁在店铺传播负能量，影响店铺氛围。', '1.店铺禁止对外议论任何人', 0, 1, 'RED', 37, '物料标准', 7, '[{"code":"M-RED-04","sourceRow":7,"title":"4.严禁在店铺传播负能量，影响店铺氛围。","checkMethod":"1.店铺禁止对外议论任何人"}]', 4),
  ('物料标准', 'M-RED-05', '5.前台不得擅自离岗,如需离岗做好岗位交接,操作台内禁止出现嘻哈,打闹或无人在岗的现象;', '5.前台不得擅自离岗,如需离岗做好岗位交接,操作台内禁止出现嘻哈,打闹或无人在岗的现象;', '1.吧台内的言行举止是否符合标准.不得在吧台内追逐，大声嬉笑打闹，影响门店形象 2.不得在吧台区域玩手机吃零食或换工作服 3.员工于操作区接打私人电话、饮食、娱乐,戴耳机听歌等行为 4.正对食品打喷嚏、咳嗽等让食品受到污染的行为', 0, 1, 'RED', 37, '物料标准', 8, '[{"code":"M-RED-05","sourceRow":8,"title":"5.前台不得擅自离岗,如需离岗做好岗位交接,操作台内禁止出现嘻哈,打闹或无人在岗的现象;","checkMethod":"1.吧台内的言行举止是否符合标准.不得在吧台内追逐，大声嬉笑打闹，影响门店形象 2.不得在吧台区域玩手机吃零食或换工作服 3.员工于操作区接打私人电话、饮食、娱乐,戴耳机听歌等行为 4.正对食品打喷嚏、咳嗽等让食品受到污染的行为"}]', 5),
  ('物料标准', 'M-RED-06', '6.小程序和各平台外卖产品10.00之前准时上架，营业时间内不可随意下架产品，如遇特殊情况请提前在群里报备(21.00前不可出现无故下架或不报备下架产品）。在营业时间内不允许私自关外卖。', '6.小程序和各平台外卖产品10.00之前准时上架，营业时间内不可随意下架产品，如遇特殊情况请提前在群里报备(21.00前不可出现无故下架或不报备下架产品）。在营业时间内不允许私自关外卖。', '1.新品上架前进行外卖编辑，需要正确规范编辑，进行外卖检查。 2.每天10.00之前准时上架，不得出现漏上架或不上架现象 3.晚上21.00后根据实际情况陆续下架产品（手作产品除外） 4.在营业时间内，不允许私自关外卖，如遇特殊原因需报备说明', 0, 1, 'RED', 37, '物料标准', 9, '[{"code":"M-RED-06","sourceRow":9,"title":"6.小程序和各平台外卖产品10.00之前准时上架，营业时间内不可随意下架产品，如遇特殊情况请提前在群里报备(21.00前不可出现无故下架或不报备下架产品）。在营业时间内不允许私自关外卖。","checkMethod":"1.新品上架前进行外卖编辑，需要正确规范编辑，进行外卖检查。 2.每天10.00之前准时上架，不得出现漏上架或不上架现象 3.晚上21.00后根据实际情况陆续下架产品（手作产品除外） 4.在营业时间内，不允许私自关外卖，如遇特殊原因需报备说明"}]', 6),
  ('物料标准', 'M-RED-07', '7.各项平台差评占比率率不得高于0.05%', '7.各项平台差评占比率率不得高于0.05%', '1.小程序,美团外卖，饿了么，抖音，美团团购,大众点评等 门店中差评占比率 =门店当月新增的与“口味”、“服务”和“出品”相关的中差评条数总和/门店当月订单数。 “中差评”定义为在平台评价中出现评分三星及以下的评价。 “口味”、“服务”和“产品”中差评的定义分别为： “口味中差评”：口味不一致、茶味淡、奶味淡、茶味浓、奶味浓、甜度淡、甜度浓等与口味相关的评价。 “服务中差评”：出餐久、出餐流程慢、不按顺序出餐、服务态度差、与客户争执、门店或台面卫生不干净、环境不佳等与服务有关的评价。 “产品中差评”：小料添加出现问题、杯型做错、温度做错、未看备注、吸管问题、包材质量问题、打包问题、包装不符或配料有问题等与产品出品有关的评价', 0, 1, 'RED', 37, '物料标准', 10, '[{"code":"M-RED-07","sourceRow":10,"title":"7.各项平台差评占比率率不得高于0.05%","checkMethod":"1.小程序,美团外卖，饿了么，抖音，美团团购,大众点评等 门店中差评占比率 =门店当月新增的与“口味”、“服务”和“出品”相关的中差评条数总和/门店当月订单数。 “中差评”定义为在平台评价中出现评分三星及以下的评价。 “口味”、“服务”和“产品”中差评的定义分别为： “口味中差评”：口味不一致、茶味淡、奶味淡、茶味浓、奶味浓、甜度淡、甜度浓等与口味相关的评价。 “服务中差评”：出餐久、出餐流程慢、不按顺序出餐、服务态度差、与客户争执、门店或台面卫生不干净、环境不佳等与服务有关的评价。 “产品中差评”：小料添加出现问题、杯型做错、温度做错、未看备注、吸管问题、包材质量问题、打包问题、包装不符或配料有问题等与产品出品有关的评价"}]', 7),
  ('物料标准', 'M-RED-08', '8.售后占比率不得高于总单量0.2%', '8.售后占比率不得高于总单量0.2%', '1.门店及线上客服售后数据统计（客观原因：小料添加出现问题、杯型做错、温度做错、吸管问题、包材质量问题、打包问题、包装不符或配料有问题等与产品出品有关的售后情况统一计算）', 0, 1, 'RED', 37, '物料标准', 11, '[{"code":"M-RED-08","sourceRow":11,"title":"8.售后占比率不得高于总单量0.2%","checkMethod":"1.门店及线上客服售后数据统计（客观原因：小料添加出现问题、杯型做错、温度做错、吸管问题、包材质量问题、打包问题、包装不符或配料有问题等与产品出品有关的售后情况统一计算）"}]', 8),
  ('物料标准', 'M-RED-09', '9.服务投诉:线上及线下', '9.服务投诉:线上及线下', '1.1-3000单以内1条，5000单以内2条，8000以内3条，10000单以内4条 (责任判定以客观的事实为依据)', 0, 1, 'RED', 37, '物料标准', 12, '[{"code":"M-RED-09","sourceRow":12,"title":"9.服务投诉:线上及线下","checkMethod":"1.1-3000单以内1条，5000单以内2条，8000以内3条，10000单以内4条 (责任判定以客观的事实为依据)"}]', 9),
  ('物料标准', 'M-RED-10', '10.沙冰机,果酱机使用标准', '10.沙冰机,果酱机使用标准', '1.沙冰壶:每次搅拌时容量不可超过2杯（禁止） 2.果酱壶:每次盛装物料不可超过总容量的60%(总容量不能超过1500毫升) 3.放入沙冰机杯子需垂直向下放置，确定连接底座无松动方可使用，沙冰机运转完后需等待机器停止平稳在取杯，避免蘑菇头损坏', 0, 1, 'RED', 37, '物料标准', 13, '[{"code":"M-RED-10","sourceRow":13,"title":"10.沙冰机,果酱机使用标准","checkMethod":"1.沙冰壶:每次搅拌时容量不可超过2杯（禁止） 2.果酱壶:每次盛装物料不可超过总容量的60%(总容量不能超过1500毫升) 3.放入沙冰机杯子需垂直向下放置，确定连接底座无松动方可使用，沙冰机运转完后需等待机器停止平稳在取杯，避免蘑菇头损坏"}]', 10),
  ('物料标准', 'M-RED-11', '11.芒果汁调兑标准', '11.芒果汁调兑标准', '1.新鲜芒果汁搅拌过滤后出芒果汁 2.芒果汁,椰奶按比例调兑好后,必须用搅棒充分搅拌均匀(禁止吧勺搅拌)', 0, 1, 'RED', 37, '物料标准', 14, '[{"code":"M-RED-11","sourceRow":14,"title":"11.芒果汁调兑标准","checkMethod":"1.新鲜芒果汁搅拌过滤后出芒果汁 2.芒果汁,椰奶按比例调兑好后,必须用搅棒充分搅拌均匀(禁止吧勺搅拌)"}]', 11),
  ('物料标准', 'M-RED-12', '12.水果存放标准', '12.水果存放标准', '1.水果进入冰箱存放时,外围需离杆,四周需离壁,避免压伤或冻坏 2.部分水果由于特性需按标准方法存放后至成熟使用,存放过程中不可出现过多损耗或人为导致损坏. (如芒果未返烧心,桃子,芭乐,猕猴桃,奇异果,新鲜牛油果捏伤等现象)', 0, 1, 'RED', 37, '物料标准', 15, '[{"code":"M-RED-12","sourceRow":15,"title":"12.水果存放标准","checkMethod":"1.水果进入冰箱存放时,外围需离杆,四周需离壁,避免压伤或冻坏 2.部分水果由于特性需按标准方法存放后至成熟使用,存放过程中不可出现过多损耗或人为导致损坏. (如芒果未返烧心,桃子,芭乐,猕猴桃,奇异果,新鲜牛油果捏伤等现象)"}]', 12),
  ('物料标准', 'M-RED-13', '13.服务核心四大原则', '13.服务核心四大原则', '顾客第一 1.前台点单同事如果备料或者忙，规定10s回头往收银台回望，第一时间接触顾客打招呼。 2.外场服务：注意力一定是在顾客身上，顾客提出问题时，及时说不好意思，先给顾客解决问题，最后感谢顾客的反馈和建议。 3.目光注意力时刻在顾客身上，遇到顾客上前咨询一定当场解决顾客疑虑，或者当顾客抱怨时第一时间进行安抚，并了解情况进行解决。 及时招呼 1，目光接触，及时跟顾客打招呼微笑。 2.前台出现三批顾客以上，一定要跟第二个顾客说声，不还意思我先给前面这个顾客点完单，再给您点看可以吗。或者提醒顾客扫码下单。 仔细聆听 1..跟顾客说话时尽量靠近一点，但是保持安全距离，整个人一定是聆听顾客讲话的姿势。并且给予回应。 2.点单同事或者外场服务时听顾客讲什么，适当回应顾客。 创造体验 1，店铺不忙的情况下饮品尽量送到顾客手上，并说一句不好意思让您久等了，祝您喝的开心! 2.打包时主动跟顾客讲特定饮品需要多长时间喝完的或者哪些东西要及时吃掉的，提升顾客体验感。 3.主动发现顾客的需求并提供解决，让顾客产生好感。', 0, 1, 'RED', 37, '物料标准', 16, '[{"code":"M-RED-13","sourceRow":16,"title":"13.服务核心四大原则","checkMethod":"顾客第一 1.前台点单同事如果备料或者忙，规定10s回头往收银台回望，第一时间接触顾客打招呼。 2.外场服务：注意力一定是在顾客身上，顾客提出问题时，及时说不好意思，先给顾客解决问题，最后感谢顾客的反馈和建议。 3.目光注意力时刻在顾客身上，遇到顾客上前咨询一定当场解决顾客疑虑，或者当顾客抱怨时第一时间进行安抚，并了解情况进行解决。 及时招呼 1，目光接触，及时跟顾客打招呼微笑。 2.前台出现三批顾客以上，一定要跟第二个顾客说声，不还意思我先给前面这个顾客点完单，再给您点看可以吗。或者提醒顾客扫码下单。 仔细聆听 1..跟顾客说话时尽量靠近一点，但是保持安全距离，整个人一定是聆听顾客讲话的姿势。并且给予回应。 2.点单同事或者外场服务时听顾客讲什么，适当回应顾客。 创造体验 1，店铺不忙的情况下饮品尽量送到顾客手上，并说一句不好意思让您久等了，祝您喝的开心! 2.打包时主动跟顾客讲特定饮品需要多长时间喝完的或者哪些东西要及时吃掉的，提升顾客体验感。 3.主动发现顾客的需求并提供解决，让顾客产生好感。"}]', 13),
  ('物料标准', 'M-RED-14', '14.证件齐全', '14.证件齐全', '1.所有营业执照有效，小餐饮许可证在有效期内，店铺员工必须持证上岗，健康证需在有效期内（老员工提前一个月办理，新员工，兼职一周内办理到位） 2.未按要求公示在消费者可见区域。 3.门店员工健康证是假证、行业类别不是食品/餐饮等视为无效。', 0, 1, 'RED', 37, '物料标准', 17, '[{"code":"M-RED-14","sourceRow":17,"title":"14.证件齐全","checkMethod":"1.所有营业执照有效，小餐饮许可证在有效期内，店铺员工必须持证上岗，健康证需在有效期内（老员工提前一个月办理，新员工，兼职一周内办理到位） 2.未按要求公示在消费者可见区域。 3.门店员工健康证是假证、行业类别不是食品/餐饮等视为无效。"}]', 14),
  ('物料标准', 'M-RED-15', '15.门店客服机畅通', '15.门店客服机畅通', '1.保证门店客服机能正常使用，保证电量有电 2.店铺电话不允许出现停机或关机状态 3.顾客找到我们这边，无论什么事，我们每个人都有责任，要主动帮助顾客去解决，不要推脱，多换位思考。', 0, 1, 'RED', 37, '物料标准', 18, '[{"code":"M-RED-15","sourceRow":18,"title":"15.门店客服机畅通","checkMethod":"1.保证门店客服机能正常使用，保证电量有电 2.店铺电话不允许出现停机或关机状态 3.顾客找到我们这边，无论什么事，我们每个人都有责任，要主动帮助顾客去解决，不要推脱，多换位思考。"}]', 15),
  ('物料标准', 'M-RED-16', '16.损害门店利益（保密制度）', '16.损害门店利益（保密制度）', '1.员工不得做出损坏店铺利益,形象和名声的任何行为,如有查实直接予以严厉处罚并开除;未经许可禁止将店铺机密透露给非工作其它人员,本店所有饮品配方等商业资料,不得拍照,复印,抄写等任何形式擅自保存,不得私自携带离开,不得提供货物给任何第三方.携带机密资料离开公司的,视情节及后果给予警告,开除并追究其相关法律责任; 2.本店所有经营收入情况资料及数据,不得提供或泄露给任何第三方,违者追究相关法律责任; 3.本店所有物资物品,不得提供或借用给任何第三方,违者追究相关法律责任; 4.使用私人手机拍摄日常备料、制作饮品等店内情况 5.私自将顾客积分积到自己（或者朋友，亲戚）会员卡', 0, 1, 'RED', 37, '物料标准', 19, '[{"code":"M-RED-16","sourceRow":19,"title":"16.损害门店利益（保密制度）","checkMethod":"1.员工不得做出损坏店铺利益,形象和名声的任何行为,如有查实直接予以严厉处罚并开除;未经许可禁止将店铺机密透露给非工作其它人员,本店所有饮品配方等商业资料,不得拍照,复印,抄写等任何形式擅自保存,不得私自携带离开,不得提供货物给任何第三方.携带机密资料离开公司的,视情节及后果给予警告,开除并追究其相关法律责任; 2.本店所有经营收入情况资料及数据,不得提供或泄露给任何第三方,违者追究相关法律责任; 3.本店所有物资物品,不得提供或借用给任何第三方,违者追究相关法律责任; 4.使用私人手机拍摄日常备料、制作饮品等店内情况 5.私自将顾客积分积到自己（或者朋友，亲戚）会员卡"}]', 16),
  ('物料标准', 'M-RED-17', '17.交叉污染', '17.交叉污染', '1.水槽严禁洗拖把，地刮，下水道部件、隔渣池，私人物品（工服，饭碗等）', 0, 1, 'RED', 37, '物料标准', 20, '[{"code":"M-RED-17","sourceRow":20,"title":"17.交叉污染","checkMethod":"1.水槽严禁洗拖把，地刮，下水道部件、隔渣池，私人物品（工服，饭碗等）"}]', 17),
  ('物料标准', 'M-RED-18', '18.食品物料存储、摆放不符合要求，且未按先进先出使用原则', '18.食品物料存储、摆放不符合要求，且未按先进先出使用原则', '1.食品/包材储存在潮湿、溅水、脏污的区域以及直接放在地上。 2.物料没有分类摆放整齐，没有先进先出使用，造成批量物料过期', 0, 1, 'RED', 37, '物料标准', 21, '[{"code":"M-RED-18","sourceRow":21,"title":"18.食品物料存储、摆放不符合要求，且未按先进先出使用原则","checkMethod":"1.食品/包材储存在潮湿、溅水、脏污的区域以及直接放在地上。 2.物料没有分类摆放整齐，没有先进先出使用，造成批量物料过期"}]', 18),
  ('物料标准', 'M-RED-19', '19.批量产品操作失误', '19.批量产品操作失误', '1.如；腌制比例不精准(糖加成盐,或者白糖油,VC粉,木薯粉等), 2.果糖机校准失误 3.茶汤比例不精准 4.水果未达到使用标准', 0, 1, 'RED', 37, '物料标准', 22, '[{"code":"M-RED-19","sourceRow":22,"title":"19.批量产品操作失误","checkMethod":"1.如；腌制比例不精准(糖加成盐,或者白糖油,VC粉,木薯粉等), 2.果糖机校准失误 3.茶汤比例不精准 4.水果未达到使用标准"}]', 19),
  ('物料标准', 'M-RED-20', '20.门店叫货出错', '20.门店叫货出错', '1.周一到周四截止16：00，周五到周六截止17：00，节假日截止到19：00，禁止加减货 2.门店货物叫多或叫少需由门店分配处理', 0, 1, 'RED', 37, '物料标准', 23, '[{"code":"M-RED-20","sourceRow":23,"title":"20.门店叫货出错","checkMethod":"1.周一到周四截止16：00，周五到周六截止17：00，节假日截止到19：00，禁止加减货 2.门店货物叫多或叫少需由门店分配处理"}]', 20),
  ('物料标准', 'M-RED-21', '21.打卡规则', '21.打卡规则', '1. 门店严禁一切代打卡行为，一经发现，将对双方当事人进行严肃处理。 2. 针对临时排休人员，一律禁止进行打卡操作。凡临时安排休息的员工，当日打卡记录一律作废，不核算任何工时与薪资，杜绝出现休班却正常计薪的考勤异常情况。（一经发现从重处理）', 0, 1, 'RED', 37, '物料标准', 24, '[{"code":"M-RED-21","sourceRow":24,"title":"21.打卡规则","checkMethod":"1. 门店严禁一切代打卡行为，一经发现，将对双方当事人进行严肃处理。 2. 针对临时排休人员，一律禁止进行打卡操作。凡临时安排休息的员工，当日打卡记录一律作废，不核算任何工时与薪资，杜绝出现休班却正常计薪的考勤异常情况。（一经发现从重处理）"}]', 21),
  ('物料标准', 'M-YELLOW-A', 'A:检查温度计使用标准：', 'A:检查温度计使用标准：', '1、使用温度计达标；（电子温度计温度在0±0.3℃，机械温度计温度应正对0℃）； 2、温度计使用、读数正确无误差；', 0, 0, 'YELLOW', 37, '物料标准', 25, '[{"code":"M-YELLOW-A","sourceRow":25,"title":"A:检查温度计使用标准：","checkMethod":"1、使用温度计达标；（电子温度计温度在0±0.3℃，机械温度计温度应正对0℃）； 2、温度计使用、读数正确无误差；"}]', 22),
  ('物料标准', 'M-YELLOW-B', 'B:检查伙伴是否在30秒内完成茶汤过滤，以及搅拌动作', 'B:检查伙伴是否在30秒内完成茶汤过滤，以及搅拌动作', '1、闷泡时间不足直接过滤茶汤、超过30秒未滤出茶汤（计时器响后30秒内滤出）； 2、搅拌均匀：茶汤加入冰块后使用搅棒，搅拌均匀且至冰块完全融化（不可直接将冰捞出）', 0, 0, 'YELLOW', 37, '物料标准', 26, '[{"code":"M-YELLOW-B","sourceRow":26,"title":"B:检查伙伴是否在30秒内完成茶汤过滤，以及搅拌动作","checkMethod":"1、闷泡时间不足直接过滤茶汤、超过30秒未滤出茶汤（计时器响后30秒内滤出）； 2、搅拌均匀：茶汤加入冰块后使用搅棒，搅拌均匀且至冰块完全融化（不可直接将冰捞出）"}]', 23),
  ('物料标准', 'M-YELLOW-C', 'C:店铺到货是否在30分钟内搬到仓库，按照物料储存标准摆放', 'C:店铺到货是否在30分钟内搬到仓库，按照物料储存标准摆放', '1.是否堆放整齐，物料按照离地10公分标准存放。 2.仓库开封物料，是否按照储存标准保存。（附上时效期）', 0, 0, 'YELLOW', 37, '物料标准', 27, '[{"code":"M-YELLOW-C","sourceRow":27,"title":"C:店铺到货是否在30分钟内搬到仓库，按照物料储存标准摆放","checkMethod":"1.是否堆放整齐，物料按照离地10公分标准存放。 2.仓库开封物料，是否按照储存标准保存。（附上时效期）"}]', 24),
  ('物料标准', 'M-YELLOW-D', 'D:工作服是否穿戴整齐。', 'D:工作服是否穿戴整齐。', '1.帽子、发帽、工服、围裙、每天需更换清洗，保持洁净状态 2.进入吧台是否正确佩戴口罩以及单手佩戴手套（早上备料需双手配套手套） 3.不允许佩戴戒指，手镯，项链，手表以及夸张的耳饰等 ，不允许做美甲', 0, 0, 'YELLOW', 37, '物料标准', 28, '[{"code":"M-YELLOW-D","sourceRow":28,"title":"D:工作服是否穿戴整齐。","checkMethod":"1.帽子、发帽、工服、围裙、每天需更换清洗，保持洁净状态 2.进入吧台是否正确佩戴口罩以及单手佩戴手套（早上备料需双手配套手套） 3.不允许佩戴戒指，手镯，项链，手表以及夸张的耳饰等 ，不允许做美甲"}]', 25),
  ('物料标准', 'M-YELLOW-E', 'E：前台，打包台，大厅不可出现堆放杂物或摆放凌乱的现象；', 'E：前台，打包台，大厅不可出现堆放杂物或摆放凌乱的现象；', '1.大厅不可堆放：扫帚，拖把及桶，拖车，空框，纸壳，玻璃刷等 2.收银台：台卡，杯架，纸巾盒，展示盒（可放置） 3.打包台：吸管架，杯套盒，易撕贴（打包贴纸）（可放置）', 0, 0, 'YELLOW', 37, '物料标准', 29, '[{"code":"M-YELLOW-E","sourceRow":29,"title":"E：前台，打包台，大厅不可出现堆放杂物或摆放凌乱的现象；","checkMethod":"1.大厅不可堆放：扫帚，拖把及桶，拖车，空框，纸壳，玻璃刷等 2.收银台：台卡，杯架，纸巾盒，展示盒（可放置） 3.打包台：吸管架，杯套盒，易撕贴（打包贴纸）（可放置）"}]', 26),
  ('物料标准', 'M-YELLOW-F', 'F：水果以及半成品是否存在过期使用现象;备料和备货是否合理', 'F：水果以及半成品是否存在过期使用现象;备料和备货是否合理', '1.备料人员是否明确告知果切台同事备料数量！不得出现盲目备料的现象！ 2.是否根据实际情况叫货,是否存在备货过多，出现超期，产生损耗现象. (水果储存不得超出最佳赏味期:如橙子常温3天,冷藏5天等) 3.备料需根据实际情况,不得超过最佳时效期（半成品时效期：如橙子角5小时 ，桑葚10小时等)', 0, 0, 'YELLOW', 37, '物料标准', 30, '[{"code":"M-YELLOW-F","sourceRow":30,"title":"F：水果以及半成品是否存在过期使用现象;备料和备货是否合理","checkMethod":"1.备料人员是否明确告知果切台同事备料数量！不得出现盲目备料的现象！ 2.是否根据实际情况叫货,是否存在备货过多，出现超期，产生损耗现象. (水果储存不得超出最佳赏味期:如橙子常温3天,冷藏5天等) 3.备料需根据实际情况,不得超过最佳时效期（半成品时效期：如橙子角5小时 ，桑葚10小时等)"}]', 27),
  ('物料标准', 'M-YELLOW-G', 'G.工作群,店长群，群里发布的任何信息，(公司所传达的工作内容)，需要仔细阅读清楚明白并传达反馈', 'G.工作群,店长群，群里发布的任何信息，(公司所传达的工作内容)，需要仔细阅读清楚明白并传达反馈', '1.阅读清楚明白后群里回复并进行传达店铺，同时需要给予反馈结果. 2.不可出现漏传或不传达的现象', 0, 0, 'YELLOW', 37, '物料标准', 31, '[{"code":"M-YELLOW-G","sourceRow":31,"title":"G.工作群,店长群，群里发布的任何信息，(公司所传达的工作内容)，需要仔细阅读清楚明白并传达反馈","checkMethod":"1.阅读清楚明白后群里回复并进行传达店铺，同时需要给予反馈结果. 2.不可出现漏传或不传达的现象"}]', 28),
  ('物料标准', 'M-YELLOW-H', 'H.美团，饿了么，大众点评，美团团购,抖音团购评价根据实际情况合理回复；平台评分时刻保持4.8分及以上（大众点评除外）', 'H.美团，饿了么，大众点评，美团团购,抖音团购评价根据实际情况合理回复；平台评分时刻保持4.8分及以上（大众点评除外）', '1.评价需当天或次日回复。外卖紧急消息第一时间回复，并明确告知同事消息情况. 2.回复步骤：一：道歉，二：给出解决方案，三：解释原因（如出现有文字评价类容，需针对性回复，不得出现文不对题或者一致模板回复）', 0, 0, 'YELLOW', 37, '物料标准', 32, '[{"code":"M-YELLOW-H","sourceRow":32,"title":"H.美团，饿了么，大众点评，美团团购,抖音团购评价根据实际情况合理回复；平台评分时刻保持4.8分及以上（大众点评除外）","checkMethod":"1.评价需当天或次日回复。外卖紧急消息第一时间回复，并明确告知同事消息情况. 2.回复步骤：一：道歉，二：给出解决方案，三：解释原因（如出现有文字评价类容，需针对性回复，不得出现文不对题或者一致模板回复）"}]', 29),
  ('物料标准', 'M-YELLOW-I', 'I.排班打卡规则', 'I.排班打卡规则', '1.员工之间如需私自换班，必须提前向店长报备，并征得同意，未经审批的私自换班一律不予认可，若产生考勤异常由本人自行承担。（店长需上报给督导）', 0, 0, 'YELLOW', 37, '物料标准', 33, '[{"code":"M-YELLOW-I","sourceRow":33,"title":"I.排班打卡规则","checkMethod":"1.员工之间如需私自换班，必须提前向店长报备，并征得同意，未经审批的私自换班一律不予认可，若产生考勤异常由本人自行承担。（店长需上报给督导）"}]', 30),
  ('物料标准', 'M-Q1.1', '检查水果半成品是否符合标准', 'Q1.1：检查水果半成品是否符合标准', 'Q1.1：1、清洗步骤是否标准; 2、成熟度是否合格； 3、切制大小符合标准/均匀；（芒果丁：0.5cm³；粗吸管可吸起） 4、果肉状态不可出现过熟或未成熟，氧化发黑变软严重； 5、榴莲解冻后需仔细检查方可使用，避免出现榴莲果核，异物，生榴莲', 5, 0, 'NORMAL', 37, '物料标准', 34, '[{"code":"Q1.1","sourceRow":34,"title":"检查水果半成品是否符合标准","checkMethod":"1、清洗步骤是否标准; 2、成熟度是否合格； 3、切制大小符合标准/均匀；（芒果丁：0.5cm³；粗吸管可吸起） 4、果肉状态不可出现过熟或未成熟，氧化发黑变软严重； 5、榴莲解冻后需仔细检查方可使用，避免出现榴莲果核，异物，生榴莲"}]', 31),
  ('物料标准', 'M-Q1.2', '检查芝士奶盖是否符合标准', 'Q1.2：检查芝士奶盖是否符合标准', 'Q1.2：1、成品奶盖表面细腻光滑、有堆叠感； 2、不可出现表面粗糙，有明显颗粒感，有肉眼可见气泡； 3、奶盖状态过稀或过干，无堆叠感或流动性差，视为不标准；', 5, 0, 'NORMAL', 37, '物料标准', 35, '[{"code":"Q1.2","sourceRow":35,"title":"检查芝士奶盖是否符合标准","checkMethod":"1、成品奶盖表面细腻光滑、有堆叠感； 2、不可出现表面粗糙，有明显颗粒感，有肉眼可见气泡； 3、奶盖状态过稀或过干，无堆叠感或流动性差，视为不标准；"}]', 32),
  ('物料标准', 'M-Q1.3', '检查板栗，芋泥，米麻薯,珍珠,山楂,糖油等半成品是否符合标准', 'Q1.3：检查板栗，芋泥，米麻薯,珍珠,山楂,糖油等半成品是否符合标准', 'Q1.3：1.制作流程是否标准; 2.成品状态是否合格; 3.口感是否存在异常; 4.储存方式是否标准; 5.板栗，芋泥搅打状态为顺滑，无颗粒状', 5, 0, 'NORMAL', 37, '物料标准', 36, '[{"code":"Q1.3","sourceRow":36,"title":"检查板栗，芋泥，米麻薯,珍珠,山楂,糖油等半成品是否符合标准","checkMethod":"1.制作流程是否标准; 2.成品状态是否合格; 3.口感是否存在异常; 4.储存方式是否标准; 5.板栗，芋泥搅打状态为顺滑，无颗粒状"}]', 33),
  ('物料标准', 'M-Q1.4-Q1.6', 'Q1.4 至 Q1.6 合并计分组', 'Q1.4：检查蒟蒻/爆珠是否符合标准；Q1.5：检查西柚粒,茶冻是否符合标准；Q1.6：检查冰块厚度标准', 'Q1.4：1、检查成品蒟蒻的完整度，不可出现漏气和变质的现象 2、蒟蒻，爆珠需将糖水沥干清洗后使用；Q1.5：1、检查成品西柚的完整度，不可出现变味的现象； 2、成品茶冻不能出现水化不成形； 3、茶冻形状不能过大（吸管可吸入大小）；Q1.6：1、检查冰块未处于8-10g，冰块完整度需达到80%；', 1, 0, 'NORMAL', 37, '物料标准', 37, '[{"code":"Q1.4","sourceRow":37,"title":"检查蒟蒻/爆珠是否符合标准","checkMethod":"1、检查成品蒟蒻的完整度，不可出现漏气和变质的现象 2、蒟蒻，爆珠需将糖水沥干清洗后使用"},{"code":"Q1.5","sourceRow":38,"title":"检查西柚粒,茶冻是否符合标准","checkMethod":"1、检查成品西柚的完整度，不可出现变味的现象； 2、成品茶冻不能出现水化不成形； 3、茶冻形状不能过大（吸管可吸入大小）"},{"code":"Q1.6","sourceRow":39,"title":"检查冰块厚度标准","checkMethod":"1、检查冰块未处于8-10g，冰块完整度需达到80%；"}]', 34),
  ('物料标准', 'M-Q2.1', '检查茶叶开封后是否严格密封保存', 'Q2.1：检查茶叶开封后是否严格密封保存', 'Q2.1：1、袋装茶叶类开封使用后是否挤出袋内空气用封口夹封存；', 2, 0, 'NORMAL', 37, '物料标准', 40, '[{"code":"Q2.1","sourceRow":40,"title":"检查茶叶开封后是否严格密封保存","checkMethod":"1、袋装茶叶类开封使用后是否挤出袋内空气用封口夹封存；"}]', 35),
  ('物料标准', 'M-Q2.2-Q2.3', 'Q2.2 至 Q2.3 合并计分组', 'Q2.2：检查茶叶、水、冰块准确称量，操作中有使用温度计并测量水温；符合泡茶标准（茶叶、水、冰块及水温请参考产品SOP）；Q2.3：检查成品茶汤及储存是否符合标准', 'Q2.2：1、称量：茶叶、冰块使用电子秤称量，称量前正确清零； 2、温度：根据茶叶属性及最佳温度（茉莉茶71-73度，栀香绿茶71-73度，红茶95度以上）进行泡制，使用温度计测量水温；开水机接出热水如温度达不到需使用电磁炉煮沸后测温量取再使用；；Q2.3：1、观察茶汤内不能出现异物、茶渣、茶叶残留； 2、茶汤是否放置保温桶冷藏储存使用； 3、是否贴上效期;', 5, 0, 'NORMAL', 37, '物料标准', 41, '[{"code":"Q2.2","sourceRow":41,"title":"检查茶叶、水、冰块准确称量，操作中有使用温度计并测量水温；符合泡茶标准（茶叶、水、冰块及水温请参考产品SOP）","checkMethod":"1、称量：茶叶、冰块使用电子秤称量，称量前正确清零； 2、温度：根据茶叶属性及最佳温度（茉莉茶71-73度，栀香绿茶71-73度，红茶95度以上）进行泡制，使用温度计测量水温；开水机接出热水如温度达不到需使用电磁炉煮沸后测温量取再使用；"},{"code":"Q2.3","sourceRow":42,"title":"检查成品茶汤及储存是否符合标准","checkMethod":"1、观察茶汤内不能出现异物、茶渣、茶叶残留； 2、茶汤是否放置保温桶冷藏储存使用； 3、是否贴上效期;"}]', 36),
  ('物料标准', 'M-Q2.4-Q2.5', 'Q2.4 至 Q2.5 合并计分组', 'Q2.4：检查产品口感试饮；Q2.5：产品操作', 'Q2.4：1、试饮门店水果茶（标准冰标准糖）； 2、试饮结果是否达标（通过稽核部伙伴进行评测）； 3、如饮品不达标，需现场进行反推制作细节，并分析原因，做重点辅导；；Q2.5：1、漏糖，多加或漏加小料 2、杯型做错 3、温度出错 4、半成品物料加错 1、产品出现串色串味（如橙子酱里面掉入桑葚，金桔与柠檬放在同一份数盒内等）', 3, 0, 'NORMAL', 37, '物料标准', 43, '[{"code":"Q2.4","sourceRow":43,"title":"检查产品口感试饮","checkMethod":"1、试饮门店水果茶（标准冰标准糖）； 2、试饮结果是否达标（通过稽核部伙伴进行评测）； 3、如饮品不达标，需现场进行反推制作细节，并分析原因，做重点辅导；"},{"code":"Q2.5","sourceRow":44,"title":"产品操作","checkMethod":"1、漏糖，多加或漏加小料 2、杯型做错 3、温度出错 4、半成品物料加错 1、产品出现串色串味（如橙子酱里面掉入桑葚，金桔与柠檬放在同一份数盒内等）"}]', 37),
  ('物料标准', 'M-Q2.6-Q3.1', 'Q2.6 至 Q3.1 合并计分组', 'Q2.6：；Q3.1：外卖回复精准度', 'Q2.6：1、摇杯力度及次数不够（不够25次，或者力度太小）；Q3.1：1、在回复外卖平台上的问题时，需要认真读懂顾客所问的疑问，不要出现同一模板，文不对题等现象', 5, 0, 'NORMAL', 37, '物料标准', 46, '[{"code":"Q2.6","sourceRow":46,"title":"","checkMethod":"1、摇杯力度及次数不够（不够25次，或者力度太小）"},{"code":"Q3.1","sourceRow":47,"title":"外卖回复精准度","checkMethod":"1、在回复外卖平台上的问题时，需要认真读懂顾客所问的疑问，不要出现同一模板，文不对题等现象"}]', 38),
  ('物料标准', 'M-Q3.2', '杯套不剪', 'Q3.2：杯套不剪', 'Q3.2：1、杯套每周一带到办公室并在杯套表上画“√”，不得出现杯套数量核对不上的状况 2、不得出现杯套未剪断的情况', 3, 0, 'NORMAL', 37, '物料标准', 48, '[{"code":"Q3.2","sourceRow":48,"title":"杯套不剪","checkMethod":"1、杯套每周一带到办公室并在杯套表上画“√”，不得出现杯套数量核对不上的状况 2、不得出现杯套未剪断的情况"}]', 39),
  ('物料标准', 'M-Q4.1', '最新SOP技能熟悉程度考核', 'Q4.1：最新SOP技能熟悉程度考核', 'Q4.1：1、随机抽取2名门店伙伴（茶饮师及以上岗位） 2、考试范围为最新SOP技能：茶汤1款，产品类1款，抽背伙伴需说出完整操作流程，注意细节描述； （打分细则：参数错一个此项不得分，操作细节错误≥2个此项不得分）', 3, 0, 'NORMAL', 37, '物料标准', 49, '[{"code":"Q4.1","sourceRow":49,"title":"最新SOP技能熟悉程度考核","checkMethod":"1、随机抽取2名门店伙伴（茶饮师及以上岗位） 2、考试范围为最新SOP技能：茶汤1款，产品类1款，抽背伙伴需说出完整操作流程，注意细节描述； （打分细则：参数错一个此项不得分，操作细节错误≥2个此项不得分）"}]', 40),
  ('卫生标准', 'H-1.1', '进货单', '门店所有货物(食品物料,包材,水果,耗材等)进货单保留24个月', '门店所有货物(食品物料,包材,水果,耗材等)进货单保留24个月', 1, 0, 'NORMAL', 63, '卫生标准', 5, '[{"code":"1.1","sourceRow":5,"title":"进货单","checkMethod":"门店所有货物(食品物料,包材,水果,耗材等)进货单保留24个月"}]', 41),
  ('卫生标准', 'H-1.2', '文件记录', '门店需有记录留档(制冰机的门店端周清记录及虫害消杀记录)', '门店需有记录留档(制冰机的门店端周清记录及虫害消杀记录)', 1, 0, 'NORMAL', 63, '卫生标准', 6, '[{"code":"1.2","sourceRow":6,"title":"文件记录","checkMethod":"门店需有记录留档(制冰机的门店端周清记录及虫害消杀记录)"}]', 42),
  ('卫生标准', 'H-2.1', '人员健康', '1)无易感染(喷嚏,持续咳嗽,咽喉炎,发烧)或传染症状(呕吐,腹泻),无开放性皮肤症状(包括刀伤,烧伤 ,抓伤,脓肿,出血等） 2）手部有伤口时没有使用亮色（不可用肉色）创可贴及佩戴手套。', '1)无易感染(喷嚏,持续咳嗽,咽喉炎,发烧)或传染症状(呕吐,腹泻),无开放性皮肤症状(包括刀伤,烧伤 ,抓伤,脓肿,出血等） 2）手部有伤口时没有使用亮色（不可用肉色）创可贴及佩戴手套。', 1, 0, 'NORMAL', 63, '卫生标准', 7, '[{"code":"2.1","sourceRow":7,"title":"人员健康","checkMethod":"1)无易感染(喷嚏,持续咳嗽,咽喉炎,发烧)或传染症状(呕吐,腹泻),无开放性皮肤症状(包括刀伤,烧伤 ,抓伤,脓肿,出血等） 2）手部有伤口时没有使用亮色（不可用肉色）创可贴及佩戴手套。"}]', 43),
  ('卫生标准', 'H-2.2', '人员着装', '1）穿戴工服（T桖，围裙)工帽,深色长裤,口罩,并穿戴包裹脚趾,脚跟的深色防滑鞋;员工须佩戴发 帽,头发不得露出;所有衣物不得带有易脱落的装饰（包括且不限于水钻，珍珠，及亮片等） 2）工服，围裙无明显污垢，无异味，工服无松脱或已脱落的口子，线口，若衣物掉色，破损严重及时更换 3）不得留长指甲，涂指甲油或戴假指甲，不得佩戴饰物（戒指，手镯，耳环等 ） 4）不得穿短裤，裙子，拖鞋等，严重损害店铺形象（以深色为主）', '1）穿戴工服（T桖，围裙)工帽,深色长裤,口罩,并穿戴包裹脚趾,脚跟的深色防滑鞋;员工须佩戴发 帽,头发不得露出;所有衣物不得带有易脱落的装饰（包括且不限于水钻，珍珠，及亮片等） 2）工服，围裙无明显污垢，无异味，工服无松脱或已脱落的口子，线口，若衣物掉色，破损严重及时更换 3）不得留长指甲，涂指甲油或戴假指甲，不得佩戴饰物（戒指，手镯，耳环等 ） 4）不得穿短裤，裙子，拖鞋等，严重损害店铺形象（以深色为主）', 3, 0, 'NORMAL', 63, '卫生标准', 10, '[{"code":"2.2","sourceRow":10,"title":"人员着装","checkMethod":"1）穿戴工服（T桖，围裙)工帽,深色长裤,口罩,并穿戴包裹脚趾,脚跟的深色防滑鞋;员工须佩戴发 帽,头发不得露出;所有衣物不得带有易脱落的装饰（包括且不限于水钻，珍珠，及亮片等） 2）工服，围裙无明显污垢，无异味，工服无松脱或已脱落的口子，线口，若衣物掉色，破损严重及时更换 3）不得留长指甲，涂指甲油或戴假指甲，不得佩戴饰物（戒指，手镯，耳环等 ） 4）不得穿短裤，裙子，拖鞋等，严重损害店铺形象（以深色为主）"}]', 44),
  ('卫生标准', 'H-2.3', '洗手消毒', '1)每次进入吧台前必须先洗手.（配置专用毛巾擦手） 2）接触食品时未佩戴一次性手套。', '1)每次进入吧台前必须先洗手.（配置专用毛巾擦手） 2）接触食品时未佩戴一次性手套。', 1, 0, 'NORMAL', 63, '卫生标准', 15, '[{"code":"2.3","sourceRow":15,"title":"洗手消毒","checkMethod":"1)每次进入吧台前必须先洗手.（配置专用毛巾擦手） 2）接触食品时未佩戴一次性手套。"}]', 45),
  ('卫生标准', 'H-2.4', '私人物品', '1）个人水杯为不易碎材质，带盖，存放固定非工作区域（指定区域存放） 2）不允许员工在食品加工区域进行与 工作无关操作（如吃喝，吸烟，使用手机，拍照和接打私人电话，玩游戏等） 3）个人物品有独立存放区域，不得出现在食品加工，销售区域，不得与货品混放', '1）个人水杯为不易碎材质，带盖，存放固定非工作区域（指定区域存放） 2）不允许员工在食品加工区域进行与 工作无关操作（如吃喝，吸烟，使用手机，拍照和接打私人电话，玩游戏等） 3）个人物品有独立存放区域，不得出现在食品加工，销售区域，不得与货品混放', 1, 0, 'NORMAL', 63, '卫生标准', 18, '[{"code":"2.4","sourceRow":18,"title":"私人物品","checkMethod":"1）个人水杯为不易碎材质，带盖，存放固定非工作区域（指定区域存放） 2）不允许员工在食品加工区域进行与 工作无关操作（如吃喝，吸烟，使用手机，拍照和接打私人电话，玩游戏等） 3）个人物品有独立存放区域，不得出现在食品加工，销售区域，不得与货品混放"}]', 46),
  ('卫生标准', 'H-2.5', '员工技能', '1）员工对产品制作（如茶汤，小料，水果等）流程熟悉并严格按照标准化，表达流畅 2）设备清洗频率及流程，认知清楚，表达流畅 3）员工对于清洗消毒流畅：清洁消毒对象，方法，频率认知清楚，表达流畅', '1）员工对产品制作（如茶汤，小料，水果等）流程熟悉并严格按照标准化，表达流畅 2）设备清洗频率及流程，认知清楚，表达流畅 3）员工对于清洗消毒流畅：清洁消毒对象，方法，频率认知清楚，表达流畅', 1, 0, 'NORMAL', 63, '卫生标准', 21, '[{"code":"2.5","sourceRow":21,"title":"员工技能","checkMethod":"1）员工对产品制作（如茶汤，小料，水果等）流程熟悉并严格按照标准化，表达流畅 2）设备清洗频率及流程，认知清楚，表达流畅 3）员工对于清洗消毒流畅：清洁消毒对象，方法，频率认知清楚，表达流畅"}]', 47),
  ('卫生标准', 'H-3.1', '合理存放', '1）分类区分存放：食品，器具，清洁用具分别隔离存放，无混放：成品，半成品，原料不能混放：清洗过的器具，工具，抹布与未清洗过的分开倒立存放 2）食品包装开封后，需分装在不锈钢或塑料有盖容器中，所有食品存放过程中应加盖或密封；（贴上开封日期） 3）包装原料和冷冻制品放入冰箱（柜）时需去除外包装（纸箱及塑料袋）。', '1）分类区分存放：食品，器具，清洁用具分别隔离存放，无混放：成品，半成品，原料不能混放：清洗过的器具，工具，抹布与未清洗过的分开倒立存放 2）食品包装开封后，需分装在不锈钢或塑料有盖容器中，所有食品存放过程中应加盖或密封；（贴上开封日期） 3）包装原料和冷冻制品放入冰箱（柜）时需去除外包装（纸箱及塑料袋）。', 1, 0, 'NORMAL', 63, '卫生标准', 24, '[{"code":"3.1","sourceRow":24,"title":"合理存放","checkMethod":"1）分类区分存放：食品，器具，清洁用具分别隔离存放，无混放：成品，半成品，原料不能混放：清洗过的器具，工具，抹布与未清洗过的分开倒立存放 2）食品包装开封后，需分装在不锈钢或塑料有盖容器中，所有食品存放过程中应加盖或密封；（贴上开封日期） 3）包装原料和冷冻制品放入冰箱（柜）时需去除外包装（纸箱及塑料袋）。"}]', 48),
  ('卫生标准', 'H-3.2', '仓库环境', '1）仓库保持干燥，干净整齐，不得出现积水，漏水，霉变等现象', '1）仓库保持干燥，干净整齐，不得出现积水，漏水，霉变等现象', 1, 0, 'NORMAL', 63, '卫生标准', 28, '[{"code":"3.2","sourceRow":28,"title":"仓库环境","checkMethod":"1）仓库保持干燥，干净整齐，不得出现积水，漏水，霉变等现象"}]', 49),
  ('卫生标准', 'H-3.3', '货架', '1）仓库货架无锈迹，无污渍；物料盛装容器（如塑料箱等二次包装容器）清洁，确认无污渍，无异味', '1）仓库货架无锈迹，无污渍；物料盛装容器（如塑料箱等二次包装容器）清洁，确认无污渍，无异味', 1, 0, 'NORMAL', 63, '卫生标准', 29, '[{"code":"3.3","sourceRow":29,"title":"货架","checkMethod":"1）仓库货架无锈迹，无污渍；物料盛装容器（如塑料箱等二次包装容器）清洁，确认无污渍，无异味"}]', 50),
  ('卫生标准', 'H-3.4', '储物柜', '1）水槽下方及其他储物柜干净无污垢，货物整齐码放；水槽下方不允许存放已开封干货物料（如茶叶，椰子粉，白砂糖等）避免受潮污染。', '1）水槽下方及其他储物柜干净无污垢，货物整齐码放；水槽下方不允许存放已开封干货物料（如茶叶，椰子粉，白砂糖等）避免受潮污染。', 1, 0, 'NORMAL', 63, '卫生标准', 30, '[{"code":"3.4","sourceRow":30,"title":"储物柜","checkMethod":"1）水槽下方及其他储物柜干净无污垢，货物整齐码放；水槽下方不允许存放已开封干货物料（如茶叶，椰子粉，白砂糖等）避免受潮污染。"}]', 51),
  ('卫生标准', 'H-3.5', '储藏规范', '1）冰箱内存放物料不得堵塞出风口 2）仓库货物堆叠不得过高，所有物料均离地10公分存放', '1）冰箱内存放物料不得堵塞出风口 2）仓库货物堆叠不得过高，所有物料均离地10公分存放', 1, 0, 'NORMAL', 63, '卫生标准', 32, '[{"code":"3.5","sourceRow":32,"title":"储藏规范","checkMethod":"1）冰箱内存放物料不得堵塞出风口 2）仓库货物堆叠不得过高，所有物料均离地10公分存放"}]', 52),
  ('卫生标准', 'H-3.6', '先进先出', '1）食品物料（包括解冻物料，开封物料）须附上正确的时间条，并注明解冻，开封，制备及到期的时间日期 ，所有移去原包装的食品必须有标注名称，生产日期，保质期，密闭保存 2）所有物料执行先进先出：根据时间标签，执行先进先出，且不可在同一物料上张贴不同时间的标签', '1）食品物料（包括解冻物料，开封物料）须附上正确的时间条，并注明解冻，开封，制备及到期的时间日期 ，所有移去原包装的食品必须有标注名称，生产日期，保质期，密闭保存 2）所有物料执行先进先出：根据时间标签，执行先进先出，且不可在同一物料上张贴不同时间的标签', 3, 0, 'NORMAL', 63, '卫生标准', 34, '[{"code":"3.6","sourceRow":34,"title":"先进先出","checkMethod":"1）食品物料（包括解冻物料，开封物料）须附上正确的时间条，并注明解冻，开封，制备及到期的时间日期 ，所有移去原包装的食品必须有标注名称，生产日期，保质期，密闭保存 2）所有物料执行先进先出：根据时间标签，执行先进先出，且不可在同一物料上张贴不同时间的标签"}]', 53),
  ('卫生标准', 'H-3.7', '储藏温度', '1）水果冷藏柜中心温度不可超过6-8度，冷冻冰箱物料中心温度-10—-18度以下（晚间不开门期间恒温达到-18度）；非门封条破损，出风口堵塞，设备未开启及设备温度设定不正确导致物料温度超标 2）小料台上冷藏物料温度均保持0度-10度之间', '1）水果冷藏柜中心温度不可超过6-8度，冷冻冰箱物料中心温度-10—-18度以下（晚间不开门期间恒温达到-18度）；非门封条破损，出风口堵塞，设备未开启及设备温度设定不正确导致物料温度超标 2）小料台上冷藏物料温度均保持0度-10度之间', 1, 0, 'NORMAL', 63, '卫生标准', 37, '[{"code":"3.7","sourceRow":37,"title":"储藏温度","checkMethod":"1）水果冷藏柜中心温度不可超过6-8度，冷冻冰箱物料中心温度-10—-18度以下（晚间不开门期间恒温达到-18度）；非门封条破损，出风口堵塞，设备未开启及设备温度设定不正确导致物料温度超标 2）小料台上冷藏物料温度均保持0度-10度之间"}]', 54),
  ('卫生标准', 'H-3.8', '解冻流程', '1）冷冻物料解冻方式正确且均在原包装内解冻 2）已解冻物料不可复冻.不可用水泡着解冻', '1）冷冻物料解冻方式正确且均在原包装内解冻 2）已解冻物料不可复冻.不可用水泡着解冻', 1, 0, 'NORMAL', 63, '卫生标准', 41, '[{"code":"3.8","sourceRow":41,"title":"解冻流程","checkMethod":"1）冷冻物料解冻方式正确且均在原包装内解冻 2）已解冻物料不可复冻.不可用水泡着解冻"}]', 55),
  ('卫生标准', 'H-4.1.1', '店铺外观', '1）店铺招牌灯箱，ＫＴ板，充电宝，菜单屏等完整无破损，无污渍 2）门口处干净，无垃圾，无污渍，地垫干净，无破损 3）门店用品（电视机，充电宝，平板，手机等）正常使用，无积灰，无污渍', '1）店铺招牌灯箱，ＫＴ板，充电宝，菜单屏等完整无破损，无污渍 2）门口处干净，无垃圾，无污渍，地垫干净，无破损 3）门店用品（电视机，充电宝，平板，手机等）正常使用，无积灰，无污渍', 1, 0, 'NORMAL', 63, '卫生标准', 43, '[{"code":"4.1.1","sourceRow":43,"title":"店铺外观","checkMethod":"1）店铺招牌灯箱，ＫＴ板，充电宝，菜单屏等完整无破损，无污渍 2）门口处干净，无垃圾，无污渍，地垫干净，无破损 3）门店用品（电视机，充电宝，平板，手机等）正常使用，无积灰，无污渍"}]', 56),
  ('卫生标准', 'H-4.1.2', '店铺内部', '1）客休区桌椅摆放整齐，及时清理台面，天花板干净无破损，无积灰，蜘蛛网。通风设备干净无破损，没有积灰。地面 清洁，无垃圾，水渍，茶渍 2）食品加工区地面清洁无垃圾，水渍，茶渍 3）操作区，备料区，客座区墙面，天花板不可有污渍，老化，脱落，发霉迹象 4）操作区如有门帘，需保持门帘清洁，无破损，无明显污渍', '1）客休区桌椅摆放整齐，及时清理台面，天花板干净无破损，无积灰，蜘蛛网。通风设备干净无破损，没有积灰。地面 清洁，无垃圾，水渍，茶渍 2）食品加工区地面清洁无垃圾，水渍，茶渍 3）操作区，备料区，客座区墙面，天花板不可有污渍，老化，脱落，发霉迹象 4）操作区如有门帘，需保持门帘清洁，无破损，无明显污渍', 2, 0, 'NORMAL', 63, '卫生标准', 46, '[{"code":"4.1.2","sourceRow":46,"title":"店铺内部","checkMethod":"1）客休区桌椅摆放整齐，及时清理台面，天花板干净无破损，无积灰，蜘蛛网。通风设备干净无破损，没有积灰。地面 清洁，无垃圾，水渍，茶渍 2）食品加工区地面清洁无垃圾，水渍，茶渍 3）操作区，备料区，客座区墙面，天花板不可有污渍，老化，脱落，发霉迹象 4）操作区如有门帘，需保持门帘清洁，无破损，无明显污渍"}]', 57),
  ('卫生标准', 'H-4.1.3', '垃圾桶', '1）垃圾桶需搭配垃圾袋使用，垃圾桶不得存放过夜垃圾，垃圾桶需加盖垃圾箱外观干净无污渍，没有破损（每日清洁擦拭消毒）', '1）垃圾桶需搭配垃圾袋使用，垃圾桶不得存放过夜垃圾，垃圾桶需加盖垃圾箱外观干净无污渍，没有破损（每日清洁擦拭消毒）', 1, 0, 'NORMAL', 63, '卫生标准', 51, '[{"code":"4.1.3","sourceRow":51,"title":"垃圾桶","checkMethod":"1）垃圾桶需搭配垃圾袋使用，垃圾桶不得存放过夜垃圾，垃圾桶需加盖垃圾箱外观干净无污渍，没有破损（每日清洁擦拭消毒）"}]', 58),
  ('卫生标准', 'H-4.1.4', '收银岗', '1）收银台整洁不凌乱，台面无污渍，无杂物，（仅限于摆放台卡，杯架，食品展盒，电脑）', '1）收银台整洁不凌乱，台面无污渍，无杂物，（仅限于摆放台卡，杯架，食品展盒，电脑）', 2, 0, 'NORMAL', 63, '卫生标准', 52, '[{"code":"4.1.4","sourceRow":52,"title":"收银岗","checkMethod":"1）收银台整洁不凌乱，台面无污渍，无杂物，（仅限于摆放台卡，杯架，食品展盒，电脑）"}]', 59),
  ('卫生标准', 'H-4.1.5', '打包区', '1）打包区域干净，包装品盛放容器干净无异物 2）规定打包毛巾叠好放整齐，只允许放打包专用抹布（蓝色专用）', '1）打包区域干净，包装品盛放容器干净无异物 2）规定打包毛巾叠好放整齐，只允许放打包专用抹布（蓝色专用）', 2, 0, 'NORMAL', 63, '卫生标准', 53, '[{"code":"4.1.5","sourceRow":53,"title":"打包区","checkMethod":"1）打包区域干净，包装品盛放容器干净无异物 2）规定打包毛巾叠好放整齐，只允许放打包专用抹布（蓝色专用）"}]', 60),
  ('卫生标准', 'H-4.1.6', '制茶岗', '1）台面，茶桶架，量杯架整洁，工具设备齐全，按要求摆放有序，干净卫生，无污渍，无积垢 2）冰槽使用后随时关门，冰槽内干净无污垢，无异物，冰块需超过1/2 3）水槽壁及底部无明显茶渍，积垢 4）上下水设备无锈迹，无破损，无渗透，干净无污渍', '1）台面，茶桶架，量杯架整洁，工具设备齐全，按要求摆放有序，干净卫生，无污渍，无积垢 2）冰槽使用后随时关门，冰槽内干净无污垢，无异物，冰块需超过1/2 3）水槽壁及底部无明显茶渍，积垢 4）上下水设备无锈迹，无破损，无渗透，干净无污渍', 2, 0, 'NORMAL', 63, '卫生标准', 55, '[{"code":"4.1.6","sourceRow":55,"title":"制茶岗","checkMethod":"1）台面，茶桶架，量杯架整洁，工具设备齐全，按要求摆放有序，干净卫生，无污渍，无积垢 2）冰槽使用后随时关门，冰槽内干净无污垢，无异物，冰块需超过1/2 3）水槽壁及底部无明显茶渍，积垢 4）上下水设备无锈迹，无破损，无渗透，干净无污渍"}]', 61),
  ('卫生标准', 'H-4.1.7', '果切台', '1）果切台地面，台面，置物架干净整洁，设备器具按要求摆放有序，干净卫生，无污渍，无积垢 2）水槽出口配备须金属过滤网使用，水槽壁及底部无明显茶渍，积垢或泛黄现象 3）上下水设备无锈迹，无破损，无渗透，干净无污渍', '1）果切台地面，台面，置物架干净整洁，设备器具按要求摆放有序，干净卫生，无污渍，无积垢 2）水槽出口配备须金属过滤网使用，水槽壁及底部无明显茶渍，积垢或泛黄现象 3）上下水设备无锈迹，无破损，无渗透，干净无污渍', 2, 0, 'NORMAL', 63, '卫生标准', 59, '[{"code":"4.1.7","sourceRow":59,"title":"果切台","checkMethod":"1）果切台地面，台面，置物架干净整洁，设备器具按要求摆放有序，干净卫生，无污渍，无积垢 2）水槽出口配备须金属过滤网使用，水槽壁及底部无明显茶渍，积垢或泛黄现象 3）上下水设备无锈迹，无破损，无渗透，干净无污渍"}]', 62),
  ('卫生标准', 'H-4.2.1', '封口机', '1）封口机外表干净无污渍,卡槽内干净卫生 2)封口机刀口干净无污渍,无锈迹', '1）封口机外表干净无污渍,卡槽内干净卫生 2)封口机刀口干净无污渍,无锈迹', 1, 0, 'NORMAL', 63, '卫生标准', 62, '[{"code":"4.2.1","sourceRow":62,"title":"封口机","checkMethod":"1）封口机外表干净无污渍,卡槽内干净卫生 2)封口机刀口干净无污渍,无锈迹"}]', 63),
