  ('卫生标准', 'H-4.3.4', '茶桶', '1)茶桶内外部干净无污渍,无茶垢,无破损 2)出水口干净无剩余茶汤 3)茶桶加盖放置,茶桶架无积垢', '1)茶桶内外部干净无污渍,无茶垢,无破损 2)出水口干净无剩余茶汤 3)茶桶加盖放置,茶桶架无积垢', 1, 0, 'NORMAL', 63, '卫生标准', 102, '[{"code":"4.3.4","sourceRow":102,"title":"茶桶","checkMethod":"1)茶桶内外部干净无污渍,无茶垢,无破损 2)出水口干净无剩余茶汤 3)茶桶加盖放置,茶桶架无积垢"}]', 77),
  ('卫生标准', 'H-4.3.5', '量杯量壶', '1)量杯量壶数字刻度标识清晰可见,无损坏,无茶垢 2)量壶加盖放置;杯架干净无茶渍,无积垢', '1)量杯量壶数字刻度标识清晰可见,无损坏,无茶垢 2)量壶加盖放置;杯架干净无茶渍,无积垢', 1, 0, 'NORMAL', 63, '卫生标准', 105, '[{"code":"4.3.5","sourceRow":105,"title":"量杯量壶","checkMethod":"1)量杯量壶数字刻度标识清晰可见,无损坏,无茶垢 2)量壶加盖放置;杯架干净无茶渍,无积垢"}]', 78),
  ('卫生标准', 'H-4.3.6', '小器具', '1)制茶岗小器具每天需用开水及专用清洁品浸泡，后勤岗的小器具需沥干存放 2小器具定点摆放，维护完好无破损，清洁干净无污渍，无茶垢', '1)制茶岗小器具每天需用开水及专用清洁品浸泡，后勤岗的小器具需沥干存放 2小器具定点摆放，维护完好无破损，清洁干净无污渍，无茶垢', 1, 0, 'NORMAL', 63, '卫生标准', 107, '[{"code":"4.3.6","sourceRow":107,"title":"小器具","checkMethod":"1)制茶岗小器具每天需用开水及专用清洁品浸泡，后勤岗的小器具需沥干存放 2小器具定点摆放，维护完好无破损，清洁干净无污渍，无茶垢"}]', 79),
  ('卫生标准', 'H-4.3.7', '抹布', '1）抹布按区域分色使用，分色清洗，消毒，1个月需更换一次。 2）门店抹布采用不掉毛，易吸水，不易损坏的材质 3）清洁抹布应单独存放在后勤岗固定位置 4）所有抹布无破损，无异味，无明显污渍', '1）抹布按区域分色使用，分色清洗，消毒，1个月需更换一次。 2）门店抹布采用不掉毛，易吸水，不易损坏的材质 3）清洁抹布应单独存放在后勤岗固定位置 4）所有抹布无破损，无异味，无明显污渍', 3, 0, 'NORMAL', 63, '卫生标准', 109, '[{"code":"4.3.7","sourceRow":109,"title":"抹布","checkMethod":"1）抹布按区域分色使用，分色清洗，消毒，1个月需更换一次。 2）门店抹布采用不掉毛，易吸水，不易损坏的材质 3）清洁抹布应单独存放在后勤岗固定位置 4）所有抹布无破损，无异味，无明显污渍"}]', 80),
  ('卫生标准', 'H-5.1', '水果储存', '1）门店储存的水果不得出现腐烂，腐败，病变，生虫等食安问题，如出现需及时废弃', '1）门店储存的水果不得出现腐烂，腐败，病变，生虫等食安问题，如出现需及时废弃', 3, 0, 'NORMAL', 63, '卫生标准', 113, '[{"code":"5.1","sourceRow":113,"title":"水果储存","checkMethod":"1）门店储存的水果不得出现腐烂，腐败，病变，生虫等食安问题，如出现需及时废弃"}]', 81),
  ('卫生标准', 'H-5.2', '物料制备', '1）原料使用前需保持包装完整无异常（如包装出现破损则不可使用） 2）制备水果物料，全程佩戴手套，不得裸手直接接触果肉（严禁用手抓取任何食品，一律使用器皿完成） 3)物料转入容器前,保证容器干净,无异物', '1）原料使用前需保持包装完整无异常（如包装出现破损则不可使用） 2）制备水果物料，全程佩戴手套，不得裸手直接接触果肉（严禁用手抓取任何食品，一律使用器皿完成） 3)物料转入容器前,保证容器干净,无异物', 2, 0, 'NORMAL', 63, '卫生标准', 114, '[{"code":"5.2","sourceRow":114,"title":"物料制备","checkMethod":"1）原料使用前需保持包装完整无异常（如包装出现破损则不可使用） 2）制备水果物料，全程佩戴手套，不得裸手直接接触果肉（严禁用手抓取任何食品，一律使用器皿完成） 3)物料转入容器前,保证容器干净,无异物"}]', 82),
  ('卫生标准', 'H-6.1', '应急药品', '1）药箱内放置常用药品，如：创口贴，烫伤膏，碘酒等 2）保证药品都在有效期内，临近效期药品及时替换 3）药箱加盖单独隔离存放', '1）药箱内放置常用药品，如：创口贴，烫伤膏，碘酒等 2）保证药品都在有效期内，临近效期药品及时替换 3）药箱加盖单独隔离存放', 1, 0, 'NORMAL', 63, '卫生标准', 117, '[{"code":"6.1","sourceRow":117,"title":"应急药品","checkMethod":"1）药箱内放置常用药品，如：创口贴，烫伤膏，碘酒等 2）保证药品都在有效期内，临近效期药品及时替换 3）药箱加盖单独隔离存放"}]', 83),
  ('卫生标准', 'H-6.2', '灭蝇灯', '1）灭蝇灯正常开启发光 2）灭蝇纸张贴效期条并在效期内，且灭蝇纸上蚊虫不超过50%', '1）灭蝇灯正常开启发光 2）灭蝇纸张贴效期条并在效期内，且灭蝇纸上蚊虫不超过50%', 1, 0, 'NORMAL', 63, '卫生标准', 120, '[{"code":"6.2","sourceRow":120,"title":"灭蝇灯","checkMethod":"1）灭蝇灯正常开启发光 2）灭蝇纸张贴效期条并在效期内，且灭蝇纸上蚊虫不超过50%"}]', 84),
  ('卫生标准', 'H-6.3', '风幕机', '1）风幕机正常开启，出风口没有明显积灰', '1）风幕机正常开启，出风口没有明显积灰', 1, 0, 'NORMAL', 63, '卫生标准', 122, '[{"code":"6.3","sourceRow":122,"title":"风幕机","checkMethod":"1）风幕机正常开启，出风口没有明显积灰"}]', 85),
  ('卫生标准', 'H-6.4', '化学药品', '1）化学药品（洗洁精，氧泡泡，柠檬酸，清洁剂等化学药品）统一定位于果切台下方柜子储存，不得存放在食品加工区域，使用完毕后，放回存放处 2）配置好的氧泡泡专用容器储存', '1）化学药品（洗洁精，氧泡泡，柠檬酸，清洁剂等化学药品）统一定位于果切台下方柜子储存，不得存放在食品加工区域，使用完毕后，放回存放处 2）配置好的氧泡泡专用容器储存', 1, 0, 'NORMAL', 63, '卫生标准', 123, '[{"code":"6.4","sourceRow":123,"title":"化学药品","checkMethod":"1）化学药品（洗洁精，氧泡泡，柠檬酸，清洁剂等化学药品）统一定位于果切台下方柜子储存，不得存放在食品加工区域，使用完毕后，放回存放处 2）配置好的氧泡泡专用容器储存"}]', 86),
  ('卫生标准', 'H-6.5', '异物防范', '1）已开封的食品（水晶粉，茶叶，西米等）需用亚克力密封箱密封储藏 2）包装材料（杯子）不用的器具等需倒扣或加盖 3）设施（糖机，蒸汽机，奶昔机等）、设备、器具未按照按标准加盖密封', '1）已开封的食品（水晶粉，茶叶，西米等）需用亚克力密封箱密封储藏 2）包装材料（杯子）不用的器具等需倒扣或加盖 3）设施（糖机，蒸汽机，奶昔机等）、设备、器具未按照按标准加盖密封', 3, 0, 'NORMAL', 63, '卫生标准', 124, '[{"code":"6.5","sourceRow":124,"title":"异物防范","checkMethod":"1）已开封的食品（水晶粉，茶叶，西米等）需用亚克力密封箱密封储藏 2）包装材料（杯子）不用的器具等需倒扣或加盖 3）设施（糖机，蒸汽机，奶昔机等）、设备、器具未按照按标准加盖密封"}]', 87),
  ('服务标准', 'S-A-01', '进店招呼', '顾客进店需礼貌主动招呼', '进店招呼—评分规则：伙伴有招呼进店顾客即得分；话术或示例：您好，欢迎光临茹菓', 5, 0, 'NORMAL', 100, '服务标准', 12, '[{"sourceRow":12,"title":"进店招呼","content":"顾客进店需礼貌主动招呼","example":"您好，欢迎光临茹菓","scoringRule":"伙伴有招呼进店顾客即得分"}]', 88),
  ('服务标准', 'S-A-02', '积极响应顾客', '推荐主打饮品&推荐顾客注册会员(告知会员福利)', '积极响应顾客—评分规则：伙伴告知顾客推荐饮品且同时向顾客推荐会员福利即得分，若缺少一项本项不得分；话术或示例：顾客咨询服务人员时，须主动告知招牌主打或新品、以及询问是否有注册过会员？没有的话可以帮助顾客免费获取,并告知会员福利', 5, 0, 'NORMAL', 100, '服务标准', 13, '[{"sourceRow":13,"title":"积极响应顾客","content":"推荐主打饮品&推荐顾客注册会员(告知会员福利)","example":"顾客咨询服务人员时，须主动告知招牌主打或新品、以及询问是否有注册过会员？没有的话可以帮助顾客免费获取,并告知会员福利","scoringRule":"伙伴告知顾客推荐饮品且同时向顾客推荐会员福利即得分，若缺少一项本项不得分"}]', 89),
  ('服务标准', 'S-A-03', '主动核餐 / 引导入座', '仔细核对产品名，温度，甜度，产品特殊口感提醒；点完单后,根据实际情况告知等待时长，小伙伴是否主动引导顾客入座', '主动核餐—评分规则：有关于口感的解释或者说明的部分得分；话术或示例：顾客如果选择半糖和3分糖，一定要提醒一下顾客，口感没那么好，：“您好半糖和3分糖的口感没那么好哦，您确定要这个甜度吗？；引导入座—评分规则：告知等待时长，并有引导入座，得5分 (若无座位情况，向顾客解释说明即可)；话术或示例：您好，请您到这边客座区休息一下(手势引导) 若门店无座，则告知:"您好暂时没有座位了，您稍等一下我们尽快为您出餐"。', 5, 0, 'NORMAL', 100, '服务标准', 14, '[{"sourceRow":14,"title":"主动核餐","content":"仔细核对产品名，温度，甜度，产品特殊口感提醒","example":"顾客如果选择半糖和3分糖，一定要提醒一下顾客，口感没那么好，：“您好半糖和3分糖的口感没那么好哦，您确定要这个甜度吗？","scoringRule":"有关于口感的解释或者说明的部分得分"},{"sourceRow":15,"title":"引导入座","content":"点完单后,根据实际情况告知等待时长，小伙伴是否主动引导顾客入座","example":"您好，请您到这边客座区休息一下(手势引导) 若门店无座，则告知:\\"您好暂时没有座位了，您稍等一下我们尽快为您出餐\\"。","scoringRule":"告知等待时长，并有引导入座，得5分 (若无座位情况，向顾客解释说明即可)"}]', 90),
  ('服务标准', 'S-A-04', '产品核对 / 饮用时间', '取茶时，主动核对顾客取单号(需要主动询问并查看顾客取餐号)；需告知顾客最佳饮用时间及方法', '产品核对—评分规则：顾客取餐时，伙伴需主动核对顾客取餐号，若未主动核对，本项不给分；话术或示例：您好帮您核对一下取餐号；饮用时间—评分规则：顾客取茶后需提醒最佳饮用时间及方法、产品承诺；话术或示例：根据饮品特性说出最佳饮用时间', 5, 0, 'NORMAL', 100, '服务标准', 16, '[{"sourceRow":16,"title":"产品核对","content":"取茶时，主动核对顾客取单号(需要主动询问并查看顾客取餐号)","example":"您好帮您核对一下取餐号","scoringRule":"顾客取餐时，伙伴需主动核对顾客取餐号，若未主动核对，本项不给分"},{"sourceRow":17,"title":"饮用时间","content":"需告知顾客最佳饮用时间及方法","example":"根据饮品特性说出最佳饮用时间","scoringRule":"顾客取茶后需提醒最佳饮用时间及方法、产品承诺"}]', 91),
  ('服务标准', 'S-A-05', '产品承诺', '取茶时承诺顾客不满意可重做', '产品承诺—评分规则：顾客取茶后需提醒最佳饮用时间及方法、产品承诺；话术或示例：您有任何不满意的地方，都可以帮您重做哦', 5, 0, 'NORMAL', 100, '服务标准', 18, '[{"sourceRow":18,"title":"产品承诺","content":"取茶时承诺顾客不满意可重做","example":"您有任何不满意的地方，都可以帮您重做哦","scoringRule":"顾客取茶后需提醒最佳饮用时间及方法、产品承诺"}]', 92),
  ('服务标准', 'S-A-06', '好评邀请', '产品递给顾客时邀好评', '好评邀请—评分规则：开口邀好评得分；话术或示例：您要是觉得好喝，麻烦您在平台上帮忙给个5星好评哦', 5, 0, 'NORMAL', 100, '服务标准', 19, '[{"sourceRow":19,"title":"好评邀请","content":"产品递给顾客时邀好评","example":"您要是觉得好喝，麻烦您在平台上帮忙给个5星好评哦","scoringRule":"开口邀好评得分"}]', 93),
  ('服务标准', 'S-A-07', '送宾语', '顾客取茶离开后送宾语欢送', '送宾语—评分规则：送宾语.；话术或示例：请慢走，欢迎下次光临', 5, 0, 'NORMAL', 100, '服务标准', 20, '[{"sourceRow":20,"title":"送宾语","content":"顾客取茶离开后送宾语欢送","example":"请慢走，欢迎下次光临","scoringRule":"送宾语."}]', 94),
  ('服务标准', 'S-A-08', '服务态度', '顾客感受门店服务态度是否热情且主动', '服务态度—评分规则：1.服务态度热情且主动得10分 2.服务态度良好或未主动得5分 3.服务态度不好且不主动0分；话术或示例：区间得分，三个区间0,5,10分', 10, 0, 'NORMAL', 100, '服务标准', 21, '[{"sourceRow":21,"title":"服务态度","content":"顾客感受门店服务态度是否热情且主动","example":"区间得分，三个区间0,5,10分","scoringRule":"1.服务态度热情且主动得10分 2.服务态度良好或未主动得5分 3.服务态度不好且不主动0分"}]', 95),
  ('服务标准', 'S-B-01', '环境维护', '设施：招牌/灯具/门窗/玻璃/装饰物/桌椅/等设施维护良好，没有损坏', '环境维护—评分规则：良好未损坏即得分', 5, 0, 'NORMAL', 100, '服务标准', 24, '[{"sourceRow":24,"title":"环境维护","content":"设施：招牌/灯具/门窗/玻璃/装饰物/桌椅/等设施维护良好，没有损坏","example":"/","scoringRule":"良好未损坏即得分"}]', 96),
  ('服务标准', 'S-B-02', '客区干净整齐', '店面客区整体卫生需干净整洁（头发/污垢/垃圾/纸屑/烟头等），桌椅摆放整齐。 （顾客离开客座区，第一时间收拾干净，桌椅归位摆放整齐）', '客区干净整齐—评分规则：顾客离店3分钟内需清理并清理干净', 10, 0, 'NORMAL', 100, '服务标准', 25, '[{"sourceRow":25,"title":"客区干净整齐","content":"店面客区整体卫生需干净整洁（头发/污垢/垃圾/纸屑/烟头等），桌椅摆放整齐。 （顾客离开客座区，第一时间收拾干净，桌椅归位摆放整齐）","example":"/","scoringRule":"顾客离店3分钟内需清理并清理干净"}]', 97),
  ('服务标准', 'S-B-03', '吧台内整洁', '顾客观察到门店吧台内物料摆放杂乱、操作台奶渍，果汁或茶汤等未清洁（做完饮品后，及时收拾）', '吧台内整洁—评分规则：一经发现即扣分（须保持随手清洁）', 10, 0, 'NORMAL', 100, '服务标准', 26, '[{"sourceRow":26,"title":"吧台内整洁","content":"顾客观察到门店吧台内物料摆放杂乱、操作台奶渍，果汁或茶汤等未清洁（做完饮品后，及时收拾）","example":"/","scoringRule":"一经发现即扣分（须保持随手清洁）"}]', 98),
