drop table if exists v40_quality_validation;

create table v40_quality_validation (
  valid_flag int not null,
  constraint chk_v40_quality_validation check (valid_flag = 1)
);

insert into v40_quality_validation(valid_flag)
select case when
  count(*) = 105
  and count(distinct code) = 105
  and sum(case when dimension = '物料标准' then 1 else 0 end) = 40
  and sum(case when dimension = '卫生标准' then 1 else 0 end) = 47
  and sum(case when dimension = '服务标准' then 1 else 0 end) = 18
  and sum(case when dimension = '物料标准' then suggested_score else 0 end) = 37.00
  and sum(case when dimension = '卫生标准' then suggested_score else 0 end) = 63.00
  and sum(case when dimension = '服务标准' then suggested_score else 0 end) = 100.00
  and sum(case when risk_level = 'RED' and red_line = 1 then 1 else 0 end) = 21
  and sum(case when risk_level = 'YELLOW' and red_line = 0 then 1 else 0 end) = 9
then 1 else 0 end
from v40_quality_item_template;

insert into inspection_standard_version(
  tenant_id, version, title, full_score, pass_score, effective_date, status, created_by
)
select tenant.id,
       '2025.11.06-R1',
       '茹菓门店品质稽核标准 2025.11.06（修正版 R1）',
       200.00,
       180.00,
       '2025-11-06',
       'DRAFT',
       null
from tenant
where not exists (
  select 1
  from inspection_standard_version existing
  where existing.tenant_id = tenant.id
    and existing.version = '2025.11.06-R1'
);

insert into inspection_standard_item(
  tenant_id, standard_version_id, dimension, code, title, description,
  check_method, suggested_score, red_line, risk_level, category_score,
  source_sheet, source_row, subitems_json, enabled, sort_order
)
select version.tenant_id,
       version.id,
       template.dimension,
       template.code,
       template.title,
       template.description,
       template.check_method,
       template.suggested_score,
       template.red_line,
       template.risk_level,
       template.category_score,
       template.source_sheet,
       template.source_row,
       template.subitems_json,
       1,
       template.sort_order
from inspection_standard_version version
cross join v40_quality_item_template template
where version.version = '2025.11.06-R1'
  and not exists (
    select 1
    from inspection_standard_item existing
    where existing.standard_version_id = version.id
      and existing.code = template.code
  );

insert into v40_quality_validation(valid_flag)
select case when
  (select count(*) from inspection_standard_version where version = '2025.11.06-R1')
    = (select count(*) from tenant)
then 1 else 0 end;

insert into v40_quality_validation(valid_flag)
select case when
  count(item.id) = 105
  and sum(case when item.dimension = '物料标准' then 1 else 0 end) = 40
  and sum(case when item.dimension = '卫生标准' then 1 else 0 end) = 47
  and sum(case when item.dimension = '服务标准' then 1 else 0 end) = 18
  and sum(case when item.dimension = '物料标准' then item.suggested_score else 0 end) = 37.00
  and sum(case when item.dimension = '卫生标准' then item.suggested_score else 0 end) = 63.00
  and sum(case when item.dimension = '服务标准' then item.suggested_score else 0 end) = 100.00
  and sum(case when item.risk_level = 'RED' and item.red_line = 1 then 1 else 0 end) = 21
  and sum(case when item.risk_level = 'YELLOW' and item.red_line = 0 then 1 else 0 end) = 9
  and max(version.full_score) = 200.00
  and max(version.pass_score) = 180.00
then 1 else 0 end
from inspection_standard_version version
left join inspection_standard_item item
  on item.standard_version_id = version.id
where version.version = '2025.11.06-R1'
group by version.id;

insert into v40_quality_validation(valid_flag)
select case when (
  select count(*)
  from inspection_standard_item item
  join v40_quality_item_template template
    on template.code = item.code
   and template.dimension = item.dimension
   and template.title = item.title
   and coalesce(template.description, '') = coalesce(item.description, '')
   and coalesce(template.check_method, '') = coalesce(item.check_method, '')
   and template.suggested_score = item.suggested_score
   and template.red_line = item.red_line
   and template.risk_level = item.risk_level
   and template.category_score = item.category_score
   and template.source_sheet = item.source_sheet
   and template.source_row = item.source_row
   and template.subitems_json = item.subitems_json
   and item.enabled = 1
   and template.sort_order = item.sort_order
  where item.standard_version_id = version.id
) = 105 then 1 else 0 end
from inspection_standard_version version
where version.version = '2025.11.06-R1';

-- Activation is deliberately last.  Any validation failure above leaves the
-- previously active standard untouched.
update inspection_standard_version
set status = 'ARCHIVED',
    updated_at = current_timestamp
where status = 'ACTIVE'
  and version <> '2025.11.06-R1';

update inspection_standard_version
set status = 'ACTIVE',
    updated_at = current_timestamp
where version = '2025.11.06-R1';

drop table v40_quality_validation;
drop table v40_quality_item_template;

